import React, { useState, useEffect } from "react";
import "./Admin.css";
import "./AdminProducts.css";

const AdminProducts = () => {
    const [products, setProducts] = useState([]);
    const [categories, setCategories] = useState([]);
    const [showModal, setShowModal] = useState(false);
    const [isEditMode, setIsEditMode] = useState(false);
    const [currentProduct, setCurrentProduct] = useState({
        product_name: "",
        brand: "",
        specs_json: "",
        unit_price: "",
        stock_quantity: "",
        warranty_period: "",
        thumbnail_url: "",
        cat_id: ""
    });

    const [search, setSearch] = useState("");

    // ================= FETCH PRODUCTS =================
    const fetchProducts = async () => {
        try {
            const token = localStorage.getItem("token"); // 🔑 Lấy token

            const res = await fetch("http://localhost:5000/api/products/products", {
                method: "GET",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}` // 🔑 Gửi token lên
                }
            });
            const data = await res.json();
            if (res.ok) {
                setProducts(Array.isArray(data) ? data : []);
            } else {
                setProducts([]);
            }
        } catch (err) {
            console.log(err);
            setProducts([]);
        }
    };

    // ================= FETCH CATEGORIES =================
    const fetchCategories = async () => {
        try {
            const token = localStorage.getItem("token"); // 🔑 Lấy token

            const res = await fetch("http://localhost:5000/api/categories/category", {
                method: "GET",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}` // 🔑 Gửi token lên
                }
            });
            const data = await res.json();
            if (res.ok) {
                setCategories(Array.isArray(data) ? data : []);
            } else {
                setCategories([]);
            }
        } catch (err) {
            console.log(err);
            setCategories([]);
        }
    };

    // ================= HANDLE SUBMIT (ADD / EDIT) =================
    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const token = localStorage.getItem("token"); // 🔑 Lấy token
            const url = isEditMode 
                ? `http://localhost:5000/api/products/${currentProduct.product_id}`
                : "http://localhost:5000/api/products";
            
            const res = await fetch(url, {
                method: isEditMode ? "PUT" : "POST",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}` // 🔑 Gửi token lên
                },
                body: JSON.stringify(currentProduct)
            });

            if (res.ok) {
                alert(isEditMode ? "Cập nhật thành công!" : "Thêm sản phẩm thành công!");
                setShowModal(false);
                fetchProducts();
            } else {
                const errData = await res.json();
                alert("Thao tác thất bại: " + errData.message);
            }
        } catch (err) {
            console.log(err);
        }
    };

    // ================= HANDLE DELETE =================
    const handleDelete = async (id) => {
        if (!window.confirm("Bạn có chắc chắn muốn xóa sản phẩm này?")) return;
        try {
            const token = localStorage.getItem("token"); // 🔑 Lấy token
            const res = await fetch(`http://localhost:5000/api/products/${id}`, {
                method: "DELETE",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}` // 🔑 Gửi token lên
                }
            });

            if (res.ok) {
                alert("Đã xóa sản phẩm!");
                fetchProducts();
            } else {
                const errData = await res.json();
                alert("Không thể xóa: " + errData.message);
            }
        } catch (err) {
            console.log(err);
        }
    };
    const handleAddClick = () => {
        setIsEditMode(false);
        setCurrentProduct({
            product_name: "",
            brand: "",
            specs_json: "",
            unit_price: "",
            stock_quantity: "",
            warranty_period: "",
            thumbnail_url: "",
            cat_id: ""
        });
        setShowModal(true);
    };
    const handleEditClick = (product) => {
        setIsEditMode(true);
        setCurrentProduct(product);
        setShowModal(true);
    };
    return (
        <div className="admin-card">
            {/* HEADER */}
                <h2>
                    Quản lý sản phẩm ({products.length})
                </h2>
            <div className="admin-card-header">
                <button
                    className="btn-add-main"
                    onClick={handleAddClick}
                >
                    + Thêm sản phẩm
                </button>
                {/* SEARCH */}

                    <input
                        type="text"
                        placeholder="Tìm tên sản phẩm..."
                        className="search-input"
                        value={search}
                        onChange={(e) =>
                            setSearch(e.target.value)
                        }
                    />
                
            </div>
            {/* TABLE */}
            <table className="admin-table">
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Ảnh</th>
                        <th>Tên sản phẩm</th>
                        <th>Danh mục</th>
                        <th>Thương hiệu</th>
                        <th>Giá</th>
                        <th>Tồn kho</th>
                        <th>Thao tác</th>
                    </tr>
                </thead>
                <tbody>
                    {products
                        .filter((p) => {
                            return p.product_name.toLowerCase().includes(search.toLowerCase());
                        })
                        .map((p) => (
                            <tr key={p.product_id}>
                                <td>#{p.product_id}</td>
                                <td>
                                    <img
                                        src={p.thumbnail_url}
                                    alt=""
                                    className="admin-product-img"
                                />
                            </td>
                            <td>{p.product_name}</td>
                            <td>{p.cat_name}</td>
                            <td>{p.brand}</td>
                            <td>
                                {Number(
                                    p.unit_price
                                ).toLocaleString()}đ
                            </td>
                            <td>{p.stock_quantity}</td>
                            <td>
                                <div className="admin-actions-cell">
                                    <button
                                        className="btn-action btn-edit"
                                        onClick={() =>
                                            handleEditClick(p)
                                        }
                                    >
                                        Sửa
                                    </button>

                                    <button
                                        className="btn-action btn-delete"
                                        onClick={() =>
                                            handleDelete(p.product_id)
                                        }
                                    >
                                        Xóa
                                    </button>
                                </div>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>

            {/* MODAL */}

            {showModal && (

                <div className="admin-modal-overlay">

                    <div className="admin-modal">

                        {/* HEADER */}

                        <div className="modal-header">

                            <h3>

                                {isEditMode
                                    ? "Chỉnh sửa sản phẩm"
                                    : "Thêm sản phẩm"}

                            </h3>

                            <button
                                className="close-x"
                                onClick={() =>
                                    setShowModal(false)
                                }
                            >
                                &times;
                            </button>

                        </div>

                        {/* FORM */}

                        <form
                            className="admin-form"
                            onSubmit={handleSubmit}
                        >

                            {/* NAME */}

                            <div className="form-group">

                                <label>Tên sản phẩm</label>

                                <input
                                    type="text"
                                    value={currentProduct.product_name}
                                    onChange={(e) =>
                                        setCurrentProduct({
                                            ...currentProduct,
                                            product_name:
                                                e.target.value
                                        })
                                    }
                                    required
                                />

                            </div>

                            {/* BRAND */}

                            <div className="form-group">

                                <label>Thương hiệu</label>

                                <input
                                    type="text"
                                    value={currentProduct.brand}
                                    onChange={(e) =>
                                        setCurrentProduct({
                                            ...currentProduct,
                                            brand: e.target.value
                                        })
                                    }
                                    required
                                />

                            </div>

                            {/* CATEGORY */}

                            <div className="form-group">

                                <label>Danh mục</label>

                                <select
                                    value={currentProduct.cat_id}
                                    onChange={(e) =>
                                        setCurrentProduct({
                                            ...currentProduct,
                                            cat_id: e.target.value
                                        })
                                    }
                                >

                                    <option value="">
                                        -- Chọn danh mục --
                                    </option>

                                    {categories.map((cat) => (

                                        <option
                                            key={cat.cat_id}
                                            value={cat.cat_id}
                                        >
                                            {cat.cat_name}
                                        </option>

                                    ))}

                                </select>

                            </div>

                            {/* PRICE */}

                            <div className="form-group">

                                <label>Giá tiền</label>

                                <input
                                    type="number"
                                    value={currentProduct.unit_price}
                                    onChange={(e) =>
                                        setCurrentProduct({
                                            ...currentProduct,
                                            unit_price:
                                                e.target.value
                                        })
                                    }
                                    required
                                />

                            </div>

                            {/* STOCK */}

                            <div className="form-group">

                                <label>Tồn kho</label>

                                <input
                                    type="number"
                                    value={currentProduct.stock_quantity}
                                    onChange={(e) =>
                                        setCurrentProduct({
                                            ...currentProduct,
                                            stock_quantity:
                                                e.target.value
                                        })
                                    }
                                    required
                                />

                            </div>

                            {/* WARRANTY */}

                            <div className="form-group">

                                <label>Bảo hành (tháng)</label>

                                <input
                                    type="number"
                                    value={currentProduct.warranty_period}
                                    onChange={(e) =>
                                        setCurrentProduct({
                                            ...currentProduct,
                                            warranty_period:
                                                e.target.value
                                        })
                                    }
                                    required
                                />

                            </div>

                            {/* IMAGE */}

                            <div className="form-group">

                                <label>URL hình ảnh</label>

                                <input
                                    type="text"
                                    value={currentProduct.thumbnail_url}
                                    onChange={(e) =>
                                        setCurrentProduct({
                                            ...currentProduct,
                                            thumbnail_url:
                                                e.target.value
                                        })
                                    }
                                    required
                                />

                            </div>

                            {/* SPECS */}

                            <div className="form-group">

                                <label>
                                    specs_json
                                </label>

                                <textarea
                                    rows="5"
                                    value={currentProduct.specs_json}
                                    onChange={(e) =>
                                        setCurrentProduct({
                                            ...currentProduct,
                                            specs_json:
                                                e.target.value
                                        })
                                    }
                                    placeholder='{"ram":"16GB","cpu":"i7"}'
                                />
                            </div>
                            {/* BUTTONS */}
                            <div className="modal-actions">

                                <button
                                    type="button"
                                    className="btn-cancel"
                                    onClick={() =>
                                        setShowModal(false)
                                    }
                                >
                                    Hủy
                                </button>
                                <button
                                    type="submit"
                                    className="btn-save"
                                >
                                    {isEditMode
                                        ? "Cập nhật"
                                        : "Thêm sản phẩm"}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};
export default AdminProducts;
